1	// claim-office.ts
2	
3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type ItemType = "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
5	type Item = {
6	  type: ItemType;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	};
11	
12	export type Damage = { itemType: ItemType; amount: number };
13	export type Incident = { cause: string; damages: Damage[] };
14	export type Policy = { items: Item[]; cap: number; remainingCap: number };
15	export type ClaimResult = { payout: number; remainingCap: number };
16	
17	const PROCESSING_FEE = 5;
18	const INSURANCE_SURCHARGE_RATE = 0.1;
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_PRICE = 60;
21	const CURSE_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
24	const LOYALTY_THRESHOLD_YEARS = 2;
25	const LOYALTY_DISCOUNT_RATE = 0.2;
26	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	function assertKnownItemTypes(items: Item[]): void {
40	  for (const item of items) {
41	    if (!(item.type in BASE_PREMIUMS)) {
42	      throw new Error(`unknown item type: ${item.type}`);
43	    }
44	  }
45	}
46	
47	function itemSurchargeRate(item: Item): number {
48	  const curseRate = item.cursed ? CURSE_SURCHARGE_RATE : 0;
49	  const highEnchantmentRate =
50	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
51	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
52	      : 0;
53	  return curseRate + highEnchantmentRate;
54	}
55	
56	function itemSurcharge(item: Item): number {
57	  return BASE_PREMIUMS[item.type] * itemSurchargeRate(item);
58	}
59	
60	function componentBlockPremium(count: number, unitPrice: number): number {
61	  return count === COMPONENT_BLOCK_SIZE
62	    ? COMPONENT_BLOCK_PRICE
63	    : count * unitPrice;
64	}
65	
66	// Sum of item base premiums (with component block discount applied,
67	// but without item-level surcharges).
68	function policyBasePremium(items: Item[]): number {
69	  const componentCounts: Record<string, number> = {};
70	  let nonComponentBase = 0;
71	  for (const item of items) {
72	    if (COMPONENT_TYPES.has(item.type)) {
73	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
74	    } else {
75	      nonComponentBase += BASE_PREMIUMS[item.type];
76	    }
77	  }
78	  const componentBase = Object.entries(componentCounts).reduce(
79	    (total, [type, count]) =>
80	      total + componentBlockPremium(count, BASE_PREMIUMS[type]),
81	    0
82	  );
83	  return nonComponentBase + componentBase;
84	}
85	
86	function totalItemSurcharges(items: Item[]): number {
87	  return items
88	    .filter((i) => !COMPONENT_TYPES.has(i.type))
89	    .reduce((total, item) => total + itemSurcharge(item), 0);
90	}
91	
92	const INSURANCE_VALUES: Record<string, number> = {
93	  sword: 1000,
94	  amulet: 600,
95	  staff: 800,
96	  potion: 400,
97	  rune: 250,
98	  moonstone: 250,
99	};
100	
101	const DEDUCTIBLE = 100;
102	const CAP_MULTIPLIER = 2;
103	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
104	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
105	
106	export function createPolicy(items: Item[]): Policy {
107	  const insuranceSum = items.reduce(
108	    (total, item) => total + INSURANCE_VALUES[item.type],
109	    0
110	  );
111	  const cap = insuranceSum * CAP_MULTIPLIER;
112	  return { items, cap, remainingCap: cap };
113	}
114	
115	function findMatchingItem(items: Item[], itemType: ItemType, used: Set<number>): Item | undefined {
116	  for (let i = 0; i < items.length; i++) {
117	    if (!used.has(i) && items[i].type === itemType) {
118	      used.add(i);
119	      return items[i];
120	    }
121	  }
122	  return undefined;
123	}
124	
125	function reimbursementForItem(item: Item, damageAmount: number): number {
126	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
127	    return damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
128	  }
129	  return damageAmount;
130	}
131	
132	export function claim(policy: Policy, incident: Incident): ClaimResult {
133	  const used = new Set<number>();
134	  let totalPayout = 0;
135	  for (const damage of incident.damages) {
136	    if (damage.amount < 0) {
137	      throw new Error(`negative damage amount: ${damage.amount}`);
138	    }
139	    const item = findMatchingItem(policy.items, damage.itemType, used);
140	    if (!item) {
141	      throw new Error(`damage references item not in policy: ${damage.itemType}`);
142	    }
143	    const reimbursement = reimbursementForItem(item, damage.amount);
144	    const afterDeductible = Math.max(0, reimbursement - DEDUCTIBLE);
145	    totalPayout += afterDeductible;
146	  }
147	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
148	  const finalPayout = Math.floor(cappedPayout);
149	  policy.remainingCap -= finalPayout;
150	  return { payout: finalPayout, remainingCap: policy.remainingCap };
151	}
152	
153	export function quote(customer: Customer, items: Item[]): number {
154	  assertKnownItemTypes(items);
155	  const policyBase = policyBasePremium(items);
156	  const itemSurcharges = totalItemSurcharges(items);
157	  const insuranceSurcharge = policyBase * INSURANCE_SURCHARGE_RATE;
158	  const loyaltyDiscount =
159	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
160	      ? policyBase * LOYALTY_DISCOUNT_RATE
161	      : 0;
162	  const followUpDiscount =
163	    (customer.previousContracts ?? 0) > 0
164	      ? policyBase * FOLLOW_UP_DISCOUNT_RATE
165	      : 0;
166	  return Math.ceil(
167	    policyBase
168	      + itemSurcharges
169	      + insuranceSurcharge
170	      - loyaltyDiscount
171	      - followUpDiscount
172	      + PROCESSING_FEE
173	  );
174	}
